#include <stdio.h>
#include <stdlib.h>
#define N 100001
#define LG 17
int adj[N][20];
int adj_size[N];
int level[N], ancestors[N][LG], n;
void dfs(int node, int parent, int lvl) {
    level[node] = lvl;
    ancestors[node][0] = parent;
    for(int i = 0; i < adj_size[node]; i++) {
        int child = adj[node][i];
        if(child != parent) {
            dfs(child, node, lvl + 1);
        }
    }
}
void preprocess() {
    for(int j = 1; j < LG; j++) {
        for(int node = 1; node <= n; node++) {
            int ancestor = ancestors[node][j - 1];
            if(ancestor == -1) {
                ancestors[node][j] = -1;
            } else {
                ancestors[node][j] = ancestors[ancestor][j - 1];
            }
        }
    }
}
int lca(int u, int v) {
    if(level[u] < level[v]) {
        int temp = u;
        u = v;
        v = temp;
    }
    int k = level[u] - level[v];
    for(int j = 0; j < LG; j++) {
        if((k & (1 << j)) != 0) {
            u = ancestors[u][j];
        }
    }
    if(u == v)
        return v;
    for(int j = LG - 1; j >= 0; j--) {
        if(ancestors[u][j] != -1 && ancestors[u][j] != ancestors[v][j]) {
            u = ancestors[u][j];
            v = ancestors[v][j];
        }
    }
    return ancestors[u][0];
}
int get_distance(int u, int v) {
    int lca_of_uv = lca(u, v);
    return level[u] + level[v] - 2 * level[lca_of_uv];
}
int main() {
    int u, v;
    scanf("%d %d %d", &n, &u, &v);
    for(int i = 1; i <= n; i++) {
        adj_size[i] = 0;
    }
    for(int i = 1; i < n; i++) {
        int ui, vi;
        scanf("%d %d", &ui, &vi);
        adj[ui][adj_size[ui]++] = vi;
        adj[vi][adj_size[vi]++] = ui;
    }
    dfs(1, -1, 0);
    preprocess();
    printf("%d\n", get_distance(u, v));
    return 0;
}

