        ancestors[node][0] = parent;
        for (int child : adj[node]) {
            if (child != parent) {
                dfs(child, node, lvl + 1);
            }
        }
    }
    static void preprocess() {
        for (int j = 1; j < LG; j++) {
            for (int node = 1; node <= n; node++) {
                int ancestor = ancestors[node][j - 1];
                ancestors[node][j] = (ancestor == -1) ? -1 : ancestors[ancestor][j - 1];
            }
        }
    }
    static int lca(int u, int v) {
        if (level[u] < level[v]) {
            int temp = u;
            u = v;
            v = temp;
        }
        int diff = level[u] - level[v];
        for (int j = 0; j < LG; j++) {
            if ((diff & (1 << j)) != 0) {
                u = ancestors[u][j];
            }
        }
        if (u == v) {
            return u;
        }
        for (int j = LG - 1; j >= 0; j--) {
            if (ancestors[u][j] != -1 && ancestors[u][j] != ancestors[v][j]) {
                u = ancestors[u][j];
                v = ancestors[v][j];
            }
        }
        return ancestors[u][0];
    }
    static int getDistance(int u, int v) {
        int lcaOfUV = lca(u, v);
        return level[u] + level[v] - 2 * level[lcaOfUV];
    }
